import{_ as t,a,b as o,c as d,d as r,e as p}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Dropbox Channel شامل کریں","description":"","frontmatter":{},"headers":[],"relativePath":"ur/upload/dropbox.md","filePath":"ur/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"ur/upload/dropbox.md"};function h(b,e,u,m,f,g){return n(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="dropbox-channel-شامل-کریں" tabindex="-1">Dropbox Channel شامل کریں <a class="header-anchor" href="#dropbox-channel-شامل-کریں" aria-label="Permalink to &quot;Dropbox Channel شامل کریں&quot;">​</a></h1><h2 id="پہلے-کیا-چاہیے" tabindex="-1">پہلے کیا چاہیے <a class="header-anchor" href="#پہلے-کیا-چاہیے" aria-label="Permalink to &quot;پہلے کیا چاہیے&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ضرورت</th><th>وجہ</th></tr></thead><tbody><tr><td>Dropbox account</td><td>sign in اور app authorize کرنے کے لیے</td></tr><tr><td>Dropbox app</td><td><code>App Key</code> اور <code>App Secret</code> generate کرنے کے لیے</td></tr><tr><td>آپ کا ImgBed domain</td><td>OAuth redirect URI کے لیے</td></tr><tr><td>دستیاب Dropbox storage</td><td>اصل file storage location کے طور پر</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-dropbox-app-بنائیں" tabindex="-1">Step 1: Dropbox App بنائیں <a class="header-anchor" href="#step-1-dropbox-app-بنائیں" aria-label="Permalink to &quot;Step 1: Dropbox App بنائیں&quot;">​</a></h3><ol><li>Dropbox App Console کھولیں:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>نیا app بنائیں۔</li><li>access type کے لیے منتخب کریں:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>app کو ایسا نام دیں جسے آپ پہچان سکیں، مثلاً <code>imgbed-app</code>۔</li><li>app بننے کے بعد app details page کھولیں۔</li></ol><p>Recommended access type:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Recommended۔ یہ ImgBed کے file storage model سے match کرتا ہے۔</td></tr><tr><td><code>Full Dropbox</code></td><td>Recommended نہیں۔ ImgBed کو پورے account access کی ضرورت نہیں۔</td></tr></tbody></table><p><img src="'+t+'" alt="Create Dropbox app" loading="lazy"></p><h3 id="step-2-redirect-uri-شامل-کریں" tabindex="-1">Step 2: Redirect URI شامل کریں <a class="header-anchor" href="#step-2-redirect-uri-شامل-کریں" aria-label="Permalink to &quot;Step 2: Redirect URI شامل کریں&quot;">​</a></h3><p>Dropbox app details page میں OAuth یا Redirect URI settings تلاش کریں اور یہ add کریں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>اگر آپ admin panel کو ایک سے زیادہ domains سے استعمال کرتے ہیں، تو ہر matching callback URL شامل کریں۔</p><p><img src="'+a+'" alt="Configure redirect URI" loading="lazy"></p><h3 id="step-3-app-permissions-configure-کریں" tabindex="-1">Step 3: App Permissions Configure کریں <a class="header-anchor" href="#step-3-app-permissions-configure-کریں" aria-label="Permalink to &quot;Step 3: App Permissions Configure کریں&quot;">​</a></h3><p><code>Permissions</code> tab کھولیں اور کم از کم یہ scopes enable کریں:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Required</th><th>Purpose</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Required</td><td>account اور quota information پڑھتا ہے</td></tr><tr><td><code>files.metadata.read</code></td><td>Required</td><td>path checks کے لیے file اور folder metadata پڑھتا ہے</td></tr><tr><td><code>files.metadata.write</code></td><td>Required</td><td>folders بناتا ہے اور metadata لکھتا ہے</td></tr><tr><td><code>files.content.write</code></td><td>Required</td><td>files upload کرتا ہے۔ یہ scope نہ ہو تو <code>required scope &#39;files.content.write&#39;</code> error آئے گا۔</td></tr><tr><td><code>files.content.read</code></td><td>Recommended</td><td>download، preview، اور temporary file links کی اجازت دیتا ہے</td></tr></tbody></table><p>scopes منتخب کرنے کے بعد page کے نیچے <code>Submit</code> پر کلک کریں۔</p><p><img src="'+o+'" alt="Add permissions" loading="lazy"></p><p>Important:</p><table tabindex="0"><thead><tr><th>Situation</th><th>What To Do</th></tr></thead><tbody><tr><td>آپ نے scopes بدلے</td><td>token authorization flow دوبارہ چلائیں اور نیا <code>Refresh Token</code> لیں۔</td></tr><tr><td>دوبارہ authorize نہیں کیا</td><td>پرانے token کو نئی permissions نہیں ملیں گی، اس لیے uploads پھر بھی fail ہو سکتے ہیں۔</td></tr></tbody></table><h3 id="step-4-app-credentials-copy-کریں" tabindex="-1">Step 4: App Credentials Copy کریں <a class="header-anchor" href="#step-4-app-credentials-copy-کریں" aria-label="Permalink to &quot;Step 4: App Credentials Copy کریں&quot;">​</a></h3><p>Dropbox app page سے یہ دو values محفوظ کریں:</p><table tabindex="0"><thead><tr><th>Dropbox Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="step-5-imgbed-میں-dropbox-channel-بھریں" tabindex="-1">Step 5: ImgBed میں Dropbox Channel بھریں <a class="header-anchor" href="#step-5-imgbed-میں-dropbox-channel-بھریں" aria-label="Permalink to &quot;Step 5: ImgBed میں Dropbox Channel بھریں&quot;">​</a></h3><p>Upload Settings میں <code>Dropbox</code> منتخب کریں اور یہ fields بھریں:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>قابل شناخت نام، مثلاً <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox کا <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox کا <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>ابھی خالی چھوڑ دیں</td></tr><tr><td>Root directory</td><td>Optional۔ default <code>imgbed</code> ہے۔</td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+d+'" alt="Get token" loading="lazy"></p><h3 id="step-6-refresh-token-حاصل-کریں" tabindex="-1">Step 6: Refresh Token حاصل کریں <a class="header-anchor" href="#step-6-refresh-token-حاصل-کریں" aria-label="Permalink to &quot;Step 6: Refresh Token حاصل کریں&quot;">​</a></h3><ol><li>ImgBed میں <code>Get Token</code> پر کلک کریں۔</li><li>جس Dropbox account کو connect کرنا ہے اس میں sign in کریں۔</li><li>authorization prompt approve کریں۔</li><li>callback page ایک <code>Refresh Token</code> دکھائے گا۔</li><li>اسے copy کریں۔</li><li>ImgBed پر واپس آ کر <code>Refresh Token</code> field میں paste کریں۔</li></ol><p><img src="'+r+'" alt="Copy token" loading="lazy"></p><h2 id="verify-کیسے-کریں" tabindex="-1">Verify کیسے کریں <a class="header-anchor" href="#verify-کیسے-کریں" aria-label="Permalink to &quot;Verify کیسے کریں&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>Save کے بعد Dropbox channel نظر آئے۔</td></tr><tr><td>Channel switch</td><td>channel enable ہو سکے۔</td></tr><tr><td>Token saved</td><td>detail page دکھائے کہ <code>Refresh Token</code> محفوظ ہو گیا ہے۔</td></tr><tr><td>Upload test</td><td>test image Dropbox app folder میں نظر آئے۔</td></tr></tbody></table><p>quota limits enabled ہوں تو quota query پر کلک کریں۔ کامیاب query کے بعد channel card used space، total space، اور last update time دکھاتا ہے۔</p><p><img src="'+p+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>ImgBed کہتا ہے configuration incomplete ہے</td><td>چیک کریں کہ <code>App Key</code>، <code>App Secret</code>، اور <code>Refresh Token</code> سب filled ہیں۔</td></tr><tr><td>Authorization کامیاب ہے مگر <code>Refresh Token</code> نہیں دکھتا</td><td><code>Get Token</code> دوبارہ کلک کریں اور یقینی بنائیں کہ offline authorization flow استعمال ہو رہا ہے۔</td></tr><tr><td>Upload <code>required scope &#39;files.content.write&#39;</code> کے ساتھ fail ہوتا ہے</td><td><code>files.content.write</code> enable کریں، <code>Submit</code> پر کلک کریں، پھر نیا <code>Refresh Token</code> لیں۔</td></tr><tr><td>Callback fail ہوتا ہے</td><td>confirm کریں کہ redirect URI <code>https://your-domain.com/api/oauth/dropbox/callback</code> ہے۔</td></tr><tr><td>Files نہیں ملتیں</td><td>confirm کریں کہ Dropbox app <code>App folder</code> mode میں بنایا گیا تھا۔</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dropbox App Console کھولیں</span></span>
<span class="line"><span>-&gt; app بنائیں</span></span>
<span class="line"><span>-&gt; App folder access منتخب کریں</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/dropbox/callback add کریں</span></span>
<span class="line"><span>-&gt; account_info.read / files.metadata.read / files.metadata.write / files.content.write enable کریں</span></span>
<span class="line"><span>-&gt; optional طور پر files.content.read enable کریں</span></span>
<span class="line"><span>-&gt; Submit پر کلک کریں</span></span>
<span class="line"><span>-&gt; App Key اور App Secret copy کریں</span></span>
<span class="line"><span>-&gt; ImgBed میں بھریں</span></span>
<span class="line"><span>-&gt; Get Token پر کلک کریں</span></span>
<span class="line"><span>-&gt; callback page سے Refresh Token copy کریں</span></span>
<span class="line"><span>-&gt; ImgBed میں paste کر کے save کریں</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const q=s(c,[["render",h]]);export{y as __pageData,q as default};
